+fn provider_source_path(
+    config: &crate::config::Config,
+    profile: &str,
+    provider_name: &str,
+) -> Option<PathBuf> {
+    if profile != "default"
+        && let Some(source) = config
+            .profiles
+            .get(profile)
+            .and_then(|profile| profile.provider_sources.get(provider_name))
+    {
+        return Some(source.clone());
+    }
+
+    config.provider_sources.get(provider_name).cloned()
+}
+
+fn resolve_password_store_dir(
+    store_dir: Option<String>,
+    provider_source: Option<PathBuf>,
+) -> Option<String> {
+    let store_dir = store_dir?;
+    let path = Path::new(&store_dir);
+    if path.is_absolute() {
+        return Some(store_dir);
+    }
+
+    let Some(provider_source) = provider_source else {
+        return Some(store_dir);
+    };
+    let Some(parent) = provider_source.parent() else {
+        return Some(store_dir);
+    };
+
+    parent
+        .join(path)
+        .to_str()
+        .map(String::from)
+        .or(Some(store_dir))
+}
