+            Some("/home/user/project/./password-store".to_string())
+        );
+    }
+
+    #[test]
+    fn leaves_absolute_password_store_dir_unchanged() {
+        let store_dir = Some("/var/lib/password-store".to_string());
+
+        assert_eq!(
+            resolve_password_store_dir(
+                store_dir.clone(),
+                Some(PathBuf::from("/home/user/project/fnox.toml")),
+            ),
+            store_dir,
+        );
+    }
