+        let store_dir = Some("./password-store".to_string());
+
+        assert_eq!(
+            resolve_password_store_dir(store_dir.clone(), None),
+            store_dir
+        );
+    }
+
+    #[test]
+    fn provider_source_path_prefers_profile_provider_source() {
+        let mut config = Config::new();
